type ViewMode = 'lobby' | 'match' | 'battle' | 'bracket';

// Persistence Keys
const STORAGE_KEY_PLAYERS = 'hok_roster_data_v2';
const STORAGE_KEY_HISTORY = 'hok_match_history_v2';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');

  // Initialize from LocalStorage or Hash
  const [players, setPlayers] = useState<Player[]>(() => {
    try {
      if (window.location.hash && window.location.hash.length > 1) {
        const hashData = window.location.hash.substring(1);
        const decoded = JSON.parse(atob(hashData));
        if (Array.isArray(decoded)) return decoded;
      }

      const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.warn("Failed to load players from storage/hash", e);
      // Fallback to local storage if hash fails
      const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    }
  });

  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY_HISTORY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [bracketMatch, setBracketMatch] = useState<BracketMatchResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isBracketMode, setIsBracketMode] = useState(false);
  const [numBracketTeams, setNumBracketTeams] = useState(4);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  // New State for Full Screen Controls
  const [isControlPanelOpen, setIsControlPanelOpen] = useState(false);

  // Confirmation Modal State
  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
    isDestructive?: boolean;
  }>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
  });

  // Sync Players to LocalStorage & URL Hash
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PLAYERS, JSON.stringify(players));

    try {
      // Create a compact version of state for hashing to avoid URL length limits
      const compactData = players.map(p => ({
        id: p.id,
        name: p.name,
        roles: p.roles,
        isAllRoles: p.isAllRoles,
        isActive: p.isActive,
        stats: p.stats
      }));
      const hash = btoa(JSON.stringify(compactData));
      if (hash.length < 2000) {
         window.history.replaceState(null, '', `#${hash}`);
      }
    } catch (e) {}
  }, [players]);

  // Sync History to LocalStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(matchHistory));
  }, [matchHistory]);

  const navigate = useCallback((mode: ViewMode, data: any) => {
    setViewMode(mode);
    if (mode === 'lobby' && Array.isArray(data)) setPlayers(data);
    else if ((mode === 'match' || mode === 'battle') && data) setCurrentMatch(data);
    else if (mode === 'bracket' && data) setBracketMatch(data);
  }, []);

  const handleBatchProcess = (batchData: { name: string; roles: Role[]; isAllRoles: boolean; action?: 'add' | 'bench' }[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { 
                ...updatedPlayers[existingIndex], 
                roles: item.roles, 
                isAllRoles: item.isAllRoles, 
                isActive: true 
              };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));

    // Also sync the name change to current active matches/brackets if applicable
    if (currentMatch) {
       setCurrentMatch(prev => {
          if (!prev) return null;
          return {
             ...prev,
             azureTeam: prev.azureTeam.map(slot => slot.player.id === updatedPlayer.id ? { ...slot, player: { ...slot.player, name: updatedPlayer.name } } : slot),
             crimsonTeam: prev.crimsonTeam.map(slot => slot.player.id === updatedPlayer.id ? { ...slot, player: { ...slot.player, name: updatedPlayer.name } } : slot)
          };
       });
    }

    if (bracketMatch) {
       setBracketMatch(prev => {
          if (!prev) return null;
          return {
             ...prev,
             teams: prev.teams.map(team => ({
                 ...team,
                 slots: team.slots.map(slot => slot.player.id === updatedPlayer.id ? { ...slot, player: { ...slot.player, name: updatedPlayer.name } } : slot)
             }))
          };
       });
    }
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    // Only validate global Room ID if NOT in Bracket Mode
    if (!isBracketMode) {
      if (!roomId.trim() || roomId.length < 4) { 
        setErrorMsg("Please enter a valid 4-digit Room ID."); 
        return; 
      }
    }

    if (isBracketMode) {
      const required = numBracketTeams * 5;
      if (activePlayers.length < required) { setErrorMsg(`Need ${required} ACTIVE players for ${numBracketTeams} teams. Current: ${activePlayers.length}`); return; }
      const result = generateBracketMatch(activePlayers, roomId, numBracketTeams);
      if (result) { 
          setBracketMatch(result); 
          setErrorMsg(null); 
          setViewMode('bracket'); 
          setIsControlPanelOpen(false); // Close modal on success
      }
      else { setErrorMsg("Failed to find valid composition."); }
    } else {
      const required = isCoachMode ? 12 : 10;
      if (activePlayers.length < required) { setErrorMsg(`Need ${required} ACTIVE players. Current: ${activePlayers.length}`); return; }
      const result = generateMatch(activePlayers, roomId, isCoachMode);
      if (result) { 
          setCurrentMatch(result); 
          setErrorMsg(null); 
          navigate('match', result); 
          setIsControlPanelOpen(false); // Close modal on success
      }
      else { setErrorMsg("Failed to find valid composition."); }
    }
  };

  const handleClearAll = () => {
    setConfirmState({
      isOpen: true,
      title: "CLEAR ROSTER",
      message: "This will permanently delete ALL players from your squad list. Are you sure you want to proceed?",
      isDestructive: true,
      onConfirm: () => setPlayers([]),
    });
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;
    const updatedMatch = {
        ...currentMatch,
        azureTeam: currentMatch.azureTeam.map(slot => (team === 'azure' && slot.role === role) ? { ...slot, player: newPlayer } : slot),
        crimsonTeam: currentMatch.crimsonTeam.map(slot => (team === 'crimson' && slot.role === role) ? { ...slot, player: newPlayer } : slot)
    };
    setCurrentMatch(updatedMatch); navigate('match', updatedMatch);
  };

  const handleBracketReroll = (teamIndex: number, role: Role, newPlayer: Player) => {
    if (!bracketMatch) return;
    const updatedTeams = bracketMatch.teams.map((team, idx) => {
        if (idx === teamIndex) {
            return {
                ...team,
                slots: team.slots.map(slot => slot.role === role ? { ...slot, player: newPlayer } : slot)
            };
        }
        return team;
    });
    setBracketMatch({ ...bracketMatch, teams: updatedTeams });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);

    const azureIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
    const crimsonIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));
    const allMatchIds = new Set([...azureIds, ...crimsonIds]);

    const updatedPlayers = players.map(p => {
      let isLastMatchMvp = mvpId === p.id;
      if (!allMatchIds.has(p.id)) return { ...p, isLastMatchMvp: false };

      const isAzure = azureIds.has(p.id);
      const isWinner = winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson'));
      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };

      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }

      return { 
        ...p, 
        stats: newStats, 
        isLastMatchMvp, 
        lastMatchRating: ratings?.[p.id] || 0 
      };
    });

    setPlayers(updatedPlayers); 
    navigate('lobby', updatedPlayers);
    setCurrentMatch(null); 
    setRoomId('');
  };

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const batchData = shuffledHeroes.slice(0, 15).map(hero => ({ name: hero.name, roles: hero.roles, isAllRoles: false, action: 'add' as const }));
     for(let i=0; i<5; i++) batchData.push({ name: `Flex Player ${i+1}`, roles: [], isAllRoles: true, action: 'add' });
     if (isCoachMode) {
        batchData.push({ name: "Coach Gemik", roles: [Role.COACH], isAllRoles: false, action: 'add' });
        batchData.push({ name: "Coach KPL", roles: [Role.COACH], isAllRoles: false, action: 'add' });
     }
     handleBatchProcess(batchData);
  };

  const handleClearHistory = () => {
    setConfirmState({
      isOpen: true,
      title: "ERASE HISTORY",
      message: "This will permanently delete all recorded battle logs. This action cannot be undone.",
      isDestructive: true,
      onConfirm: () => setMatchHistory([]),
    });
  };

  const isRoomReady = roomId.length === 4;

  const copyShareLink = () => {
    navigator.clipboard.writeText(window.location.href);
    alert("Share link copied to clipboard!");
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <WIBClock />

      <ConfirmModal 
        isOpen={confirmState.isOpen}
        title={confirmState.title}
        message={confirmState.message}
        onConfirm={confirmState.onConfirm}
        onCancel={() => setConfirmState(prev => ({ ...prev, isOpen: false }))}
        isDestructive={confirmState.isDestructive}
      />

      {/* Background Image & Overlay */}
      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />}

      {/* NEW FULL SCREEN CONTROL PANEL MODAL */}
      <LobbyControlModal 
        isOpen={isControlPanelOpen}
        onClose={() => setIsControlPanelOpen(false)}
        isBracketMode={isBracketMode}
        setIsBracketMode={setIsBracketMode}
        isCoachMode={isCoachMode}
        setIsCoachMode={setIsCoachMode}
        roomId={roomId}
        setRoomId={setRoomId}
        isRoomReady={isRoomReady}
        numBracketTeams={numBracketTeams}
        setNumBracketTeams={setNumBracketTeams}
        playersLength={players.length}
        activePlayersLength={activePlayers.length}
        onBatchProcess={handleBatchProcess}
        quickFill={quickFill}
        onGenerate={handleGenerate}
        errorMsg={errorMsg}
        copyShareLink={copyShareLink}
      />

      {viewMode === 'lobby' && (
        <>
          <main className="relative z-10 pt-16 px-6 flex-grow w-full">
            <div className="flex flex-col gap-6 w-full">

                 {/* HEADER AREA */}
                 <div className="flex flex-col md:flex-row items-center justify-between gap-4 mb-2">
                    <div>
                      <h2 className="text-3xl md:text-4xl font-cinzel font-black text-[#dcb06b] drop-shadow-[0_0_10px_rgba(220,176,107,0.5)]">SQUAD ROSTER</h2>
                      <div className="h-1 w-24 bg-gradient-to-r from-[#dcb06b] to-transparent mt-1"></div>
                    </div>

                    <div className="flex gap-4 items-center">
                        <button onClick={handleClearAll} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase transition-colors font-bold tracking-widest border border-[#1e3a5f] px-4 py-2 hover:border-red-500">
                           CLEAR ROSTER
                        </button>

                        {/* MAIN ACTION BUTTON TO OPEN COMMAND CENTER */}
                        <button 
                            onClick={() => setIsControlPanelOpen(true)}
                            className="group relative px-6 py-3 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-sm hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_15px_rgba(220,176,107,0.3)] animate-pulse-fast"
                        >
                            <span className="relative z-10 flex items-center gap-2 font-cinzel font-black tracking-widest text-sm">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                                COMMAND CENTER
                            </span>
                        </button>
                    </div>
                 </div>

                 {/* ROSTER LIST - FULL WIDTH */}
                 <div className="tech-border p-6 bg-[#0a1a2f]/40 min-h-[600px] w-full">
                    <PlayerList 
                        players={players} 
                        onRemove={removePlayer} 
                        onToggleActive={togglePlayerActive} 
                        onEdit={handleEditPlayer} 
                        isSidebarOpen={false} // Always false now as sidebar is gone
                    />
                 </div>

                 {/* HISTORY SECTION */}
                 <div className="mt-8 tech-border p-6 bg-[#0a1a2f]/40">
                    <h2 className="text-2xl font-cinzel font-black text-[#dcb06b] mb-6">BATTLE HISTORY</h2>
                    <HistoryList history={matchHistory} onClear={handleClearHistory} />
                 </div>
            </div>
          </main>

          <footer className="py-12 px-6 text-center border-t border-[#dcb06b]/10 bg-[#05090f] mt-auto">
              <div className="max-w-4xl mx-auto flex flex-col items-center gap-4">
                  <div className="w-12 h-0.5 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent mb-2"></div>
                  <div className="text-[#dcb06b] font-cinzel font-black text-sm tracking-[0.2em] mb-1">
                      APPLICATION DEVELOPED BY KAZEHUNT
                  </div>
                  <div className="text-[#4a5f78] font-orbitron text-[9px] leading-relaxed tracking-[0.1em] uppercase max-w-2xl flex flex-col gap-2">
                      <p>DESIGNED EXCLUSIVELY FOR HONOR OF KINGS CUSTOM FUN MATCHES ON THE OFFICIAL DISCORD. THE DEVELOPER ASSUMES NO RESPONSIBILITY FOR USAGE OUTSIDE THIS INTENDED SCOPE.</p>
                  </div>
              </div>
          </footer>
        </>
      )}

      {currentMatch && viewMode !== 'lobby' && viewMode !== 'bracket' && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={() => { setCurrentMatch(null); setViewMode('lobby'); }}
          onCompleteMatch={handleMatchFinish}
          onReroll={handleRerollSlot}
          onStartBattle={() => setViewMode('battle')}
          onUpdatePlayer={handleUpdatePlayer}
        />
      )}

      {bracketMatch && viewMode === 'bracket' && (
        <BracketDisplay 
          match={bracketMatch} 
          onReset={() => { setBracketMatch(null); setViewMode('lobby'); }} 
          activePlayers={activePlayers}
          onReroll={handleBracketReroll}
          onUpdatePlayer={handleUpdatePlayer}
        />
      )}

      <style>{`
        @keyframes chromatic {
          0% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
          25% { text-shadow: -2px 0 0 #ff0000, 2px 0 0 #0000ff; }
          50% { text-shadow: 2px -1px 0 #ff0000, -2px 1px 0 #0000ff; }
          75% { text-shadow: -2px 1px 0 #ff0000, 2px -1px 0 #0000ff; }
          100% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
        }
        @keyframes fade-in {
          from { opacity: 0; }
          to { opacity: 1; }
        }
      `}</style>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const handleFilterClick = (val: string) => {
      setFilter(val as FilterType);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;

    // Pastikan panah dirender dua kali jika nilai mutlaknya adalah 2
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400 items-center justify-center">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500 items-center justify-center">
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  // UPDATED GRID CLASSES: Always assume a wide layout now
  const gridClasses = "grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 min-[1800px]:grid-cols-7 min-[2200px]:grid-cols-8";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => handleFilterClick(val)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-4 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';
          let primaryColor = '';

          // Hirarki Status & Warna Trace Border
          if (player.isActive) {
            if (isMvp) {
              primaryColor = '#fbbf24'; // Emas
              glowColor = 'drop-shadow-[0_0_12px_#fbbf24]';
            } else if (isCoach) {
              primaryColor = '#ffffff'; // Putih
              glowColor = 'drop-shadow-[0_0_12px_rgba(255,255,255,0.6)]';
            } else if (ws >= 2) {
              if (ws >= 5) primaryColor = '#ef4444'; // Merah
              else if (ws >= 4) primaryColor = '#f97316'; // Oren
              else if (ws >= 3) primaryColor = '#a855f7'; // Ungu
              else primaryColor = '#00d2ff'; // Biru Cyan

              glowColor = `drop-shadow-[0_0_10px_${primaryColor}]`;
            }

            if (primaryColor) {
               animationLayer = (
                 <div 
                   className="absolute inset-[-150%] animate-[spin_4s_linear_infinite]"
                   style={{
                     background: `conic-gradient(from 0deg, ${primaryColor} 0deg, ${primaryColor} 40deg, transparent 40deg, transparent 180deg, ${primaryColor} 180deg, ${primaryColor} 220deg, transparent 220deg, transparent 360deg)`
                   }}
                 />
               );
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>
              {/* Animated Border Background */}
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]/20">
                 {animationLayer}
              </div>

              {/* Inner Card content */}
              <div className={`absolute inset-[2px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/80 grayscale backdrop-blur-sm'}`}>

                {/* BENCHED STAMP - Only for inactive players */}
                {!player.isActive && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center pointer-events-none overflow-hidden">
                        <div className="absolute inset-0 bg-red-900/10 mix-blend-overlay"></div>
                        <div className="rotate-[-15deg] border-4 border-red-600/80 px-4 py-1 text-red-600/90 font-black text-2xl tracking-[0.3em] uppercase bg-black/40 backdrop-blur-sm shadow-[0_0_20px_rgba(220,38,38,0.4)] animate-pulse-fast">
                            BENCHED
                        </div>
                    </div>
                )}

                <div className="flex justify-between items-start mb-2 relative z-10">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase ${getRoleBadgeStyle(r)}`}>{r.split(' ')[0]}</span>)
                      )}
                    </div>
                  </div>

                  {/* Status Mini-Tags */}
                  <div className="flex flex-col items-end gap-1">
                    <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b] mb-1">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg>
                    </button>

                    <div className="flex flex-col gap-1 items-end">
                       {/* MVP Mini-Tag */}
                       {isMvp && player.isActive && (
                         <div className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter bg-[#fbbf24] text-black clip-corner-sm shadow-[0_0_8px_rgba(251,191,36,0.6)]">
                            MVP
                         </div>
                       )}

                       {/* Win Streak Mini-Tag */}
                       {ws >= 2 && player.isActive && (
                         <div 
                           className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter text-white clip-corner-sm shadow-md"
                           style={{ backgroundColor: primaryColor }}
                         >
                            {ws} WS
                         </div>
                       )}
                    </div>
                  </div>
                </div>

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1 relative z-10">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => { onToggleActive(menuOpenId); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => { onEdit(players.find(p => p.id === menuOpenId)!); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => { onRemove(menuOpenId); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};
